mapper.select:
select count(*) from user_details d join users u on d.user_id = u.id
and d.user_name like concat('%', #{userName}, '%')
and d.mailaddress like concat('%', #{mailaddress}, '%')
and d.pref_cd = #{prefCd}
and d.gender = ${@java.lang.Integer@valueOf(gender)}
and exists ( select * from user_additions where user_id = u.id
#{addition}
)

select u.id user_id , u.user_cd , d.user_name , d.mailaddress , d.pref_cd , d.address , d.gender , d.note , string_agg(a.addition, ',' order by a.addition) additions from user_details d join users u on d.user_id = u.id left join user_additions a on a.user_id = u.id
and d.user_name like concat('%', #{userName}, '%')
and d.mailaddress like concat('%', #{mailaddress}, '%')
and d.pref_cd = #{prefCd}
and d.gender = ${@java.lang.Integer@valueOf(gender)}
and exists ( select * from user_additions where user_id = u.id
#{addition}
)
group by u.id , u.user_cd , d.user_name , d.mailaddress , d.pref_cd , d.address , d.gender , d.note order by u.user_cd
offset ${page * size} limit ${size}
